154	void cublasMMWrapper::Gemm(cublasOperation_t transa,
155	                           cublasOperation_t transb,
156	                           const int         m,
157	                           const int         n,
158	                           const int         k,
159	                           const void*       A,
160	                           const int         lda,
161	                           const void*       B,
162	                           const int         ldb,
163	                           void*             C,
164	                           const int         ldc,
165	                           float             f_alpha,
166	                           float             f_beta)
167	{
168	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
169	    half h_alpha = (half)(f_alpha);
170	    half h_beta  = (half)(f_beta);
171	
172	    mu_->lock();
173	    // TODO: default cublas libs
174	    int  is_fp16_computeType = computeType_ == CUDA_R_16F ? 1 : 0;
175	    bool using_cublasLt      = (Atype_ == CUDA_R_16F) ? true : false;
176	    int  batch_count         = 1;
177	    // fp32 use cublas as default
178	    // fp16 use cublasLt as default
179	    const void* alpha = is_fp16_computeType ? reinterpret_cast<void*>(&h_alpha) : reinterpret_cast<void*>(&f_alpha);
180	    const void* beta  = is_fp16_computeType ? reinterpret_cast<void*>(&h_beta) : reinterpret_cast<void*>(&f_beta);
181	
182	    int findAlgo = cublas_algo_map_->isExist(batch_count, m, n, k, getCublasDataType(Atype_));
183	
184	    cublasLtMatmulAlgo_info info = cublas_algo_map_->getAlgo(batch_count, m, n, k, getCublasDataType(Atype_));
185	    if (findAlgo) {
186	        if (info.stages != -1) {
187	            using_cublasLt = true;
188	        }
189	        else {
190	            using_cublasLt = false;
191	        }
192	    }
193	
194	    if (using_cublasLt) {
195	        cublasLtMatmulDesc_t   operationDesc = NULL;
196	        cublasLtMatrixLayout_t Adesc = NULL, Bdesc = NULL, Cdesc = NULL;
197	        cudaDataType_t         scaleType;
198	#if (CUDART_VERSION >= 11000)
199	        cublasComputeType_t computeType;
200	#else
201	        cudaDataType_t computeType;
202	#endif
203	
204	        if (is_fp16_computeType) {
205	#if (CUDART_VERSION >= 11000)
206	            computeType = CUBLAS_COMPUTE_16F;
207	#else
208	            computeType = CUDA_R_16F;
209	#endif
210	            scaleType = CUDA_R_16F;
211	        }
212	        else {
213	#if (CUDART_VERSION >= 11000)
214	            computeType = CUBLAS_COMPUTE_32F;
215	#else
216	            computeType = CUDA_R_32F;
217	#endif
218	            scaleType = CUDA_R_32F;
219	        }
220	
221	        // --------------------------------------
222	        // Create descriptors for the original matrices
223	        cublasLtMatrixLayoutCreate(&Adesc, Atype_, transa == CUBLAS_OP_N ? m : k, transa == CUBLAS_OP_N ? k : m, lda);
224	        cublasLtMatrixLayoutCreate(&Bdesc, Btype_, transb == CUBLAS_OP_N ? k : n, transb == CUBLAS_OP_N ? n : k, ldb);
225	        cublasLtMatrixLayoutCreate(&Cdesc, Ctype_, m, n, ldc);
226	#if (CUDART_VERSION >= 11000)
227	        cublasLtMatmulDescCreate(&operationDesc, computeType, scaleType);
228	#else
229	        cublasLtMatmulDescCreate(&operationDesc, computeType);
230	#endif
231	
232	        cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSA, &transa, sizeof(cublasOperation_t));
233	        cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSB, &transb, sizeof(cublasOperation_t));
234	
235	        cublasLtMatmulAlgo_t algo;
236	        void*                workSpace     = cublas_workspace_;
237	        int                  workspaceSize = cublas_workspace_ == NULL ? 0 : CUBLAS_WORKSPACE_SIZE;
238	        if (findAlgo) {
239	            if (info.workspaceSize > workspaceSize) {
240	                findAlgo = 0;
241	            }
242	            else {
243	                cublasLtMatmulAlgoInit(
244	                    cublaslt_handle_, computeType, scaleType, Atype_, Btype_, Ctype_, Ctype_, info.algoId, &algo);
245	                cublasLtMatmulAlgoConfigSetAttribute(
246	                    &algo, CUBLASLT_ALGO_CONFIG_CUSTOM_OPTION, &(info.customOption), sizeof(info.customOption));
247	                cublasLtMatmulAlgoConfigSetAttribute(
248	                    &algo, CUBLASLT_ALGO_CONFIG_TILE_ID, &(info.tile), sizeof(info.tile));
249	                cublasLtMatmulAlgoConfigSetAttribute(
250	                    &algo, CUBLASLT_ALGO_CONFIG_SPLITK_NUM, &(info.splitK_val), sizeof(info.splitK_val));
251	                cublasLtMatmulAlgoConfigSetAttribute(
252	                    &algo, CUBLASLT_ALGO_CONFIG_CTA_SWIZZLING, &(info.swizzle), sizeof(info.swizzle));
253	                cublasLtMatmulAlgoConfigSetAttribute(&algo,
254	                                                     CUBLASLT_ALGO_CONFIG_REDUCTION_SCHEME,
255	                                                     &(info.reductionScheme),
256	                                                     sizeof(info.reductionScheme));
257	
258	#if (CUDART_VERSION >= 11000)
259	                cublasLtMatmulAlgoConfigSetAttribute(
260	                    &algo, CUBLASLT_ALGO_CONFIG_STAGES_ID, &(info.stages), sizeof(info.stages));
261	#endif
262	
263	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
264	                cublasLtMatmulAlgoConfigSetAttribute(
265	                    &algo, CUBLASLT_ALGO_CONFIG_INNER_SHAPE_ID, &(info.inner_shapeId), sizeof(info.inner_shapeId));
266	                cublasLtMatmulAlgoConfigSetAttribute(&algo,
267	                                                     CUBLASLT_ALGO_CONFIG_CLUSTER_SHAPE_ID,
268	                                                     &(info.cluster_shapeId),
269	                                                     sizeof(info.cluster_shapeId));
270	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
271	                cublasLtMatmulAlgoConfigSetAttribute(
272	                    &algo, CUBLASLT_ALGO_CONFIG_MMA_SHAPE_ID, &(info.mma_shapeId), sizeof(info.mma_shapeId));
273	                cublasLtMatmulAlgoConfigSetAttribute(
274	                    &algo, CUBLASLT_ALGO_CONFIG_CGA_SHAPE_ID, &(info.cga_shapeId), sizeof(info.cga_shapeId));
275	                cublasLtMatmulAlgoConfigSetAttribute(
276	                    &algo, CUBLASLT_ALGO_CONFIG_SCHEDULING_MODE, &(info.sche_mode), sizeof(info.sche_mode));
277	#endif
278	            }
279	        }
280	
281	        cublasLtMatmul(cublaslt_handle_,
282	                       operationDesc,
283	                       alpha,
284	                       A,
285	                       Adesc,
286	                       B,
287	                       Bdesc,
288	                       beta,
289	                       C,
290	                       Cdesc,
291	                       C,
292	                       Cdesc,
293	                       (findAlgo == 1 ? (&algo) : NULL),
294	                       workSpace,
295	                       workspaceSize,
296	                       stream_);
297	
298	        cublasLtMatmulDescDestroy(operationDesc);
299	        cublasLtMatrixLayoutDestroy(Adesc);
300	        cublasLtMatrixLayoutDestroy(Bdesc);
301	        cublasLtMatrixLayoutDestroy(Cdesc);
302	        sync_check_cuda_error();
303	    }
304	    else {
305	        int cublasAlgo = info.algoId;
306	        check_cuda_error(cublasGemmEx(cublas_handle_,
307	                                      transa,
308	                                      transb,
309	                                      m,
310	                                      n,
311	                                      k,
312	                                      alpha,
313	                                      A,
314	                                      Atype_,
315	                                      lda,
316	                                      B,
317	                                      Btype_,
318	                                      ldb,
319	                                      beta,
320	                                      C,
321	                                      Ctype_,
322	                                      ldc,
323	                                      computeType_,
324	                                      static_cast<cublasGemmAlgo_t>(cublasAlgo)));
325	        sync_check_cuda_error();
326	    }
327	    mu_->unlock();
328	}
329	
330	void cublasMMWrapper::setFP32GemmConfig()
