386	void cublasMMWrapper::Gemm(cublasOperation_t transa,
387	                           cublasOperation_t transb,
388	                           const int         m,
389	                           const int         n,
390	                           const int         k,
391	                           const void*       A,
392	                           const int         lda,
393	                           const void*       B,
394	                           const int         ldb,
395	                           const void*       bias,
396	                           void*             C,
397	                           const int         ldc)
398	{
399	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
400	    cudaDataType_t      Atype, Btype, Ctype;
401	    cublasComputeType_t computeType;
402	    cudaDataType_t      scaleType;
403	    float               alpha_float = 1.0f;
404	    float               beta_float  = 0.0f;
405	    half                alpha_half  = half(1.0f);
406	    half                beta_half   = half(0.0f);
407	    void *              alpha, *beta;
408	
409	    // int is_fp16_computeType = computeType_ == CUDA_R_16F ? 1 : 0;
410	    if (Atype_ == CUDA_R_32F) {
411	        computeType = CUBLAS_COMPUTE_32F_FAST_TF32;
412	        Atype       = CUDA_R_32F;
413	        Btype       = CUDA_R_32F;
414	        Ctype       = CUDA_R_32F;
415	        scaleType   = CUDA_R_32F;
416	        alpha       = &alpha_float;
417	        beta        = &beta_float;
418	    }
419	    else if (Atype_ == CUDA_R_16BF) {
420	        computeType = CUBLAS_COMPUTE_32F_FAST_TF32;
421	        Atype       = CUDA_R_16BF;
422	        Btype       = CUDA_R_16BF;
423	        Ctype       = CUDA_R_16BF;
424	        scaleType   = CUDA_R_32F;
425	        alpha       = &alpha_float;
426	        beta        = &beta_float;
427	    }
428	    else {
429	        computeType = CUBLAS_COMPUTE_16F;
430	        Atype       = CUDA_R_16F;
431	        Btype       = CUDA_R_16F;
432	        Ctype       = CUDA_R_16F;
433	        scaleType   = CUDA_R_16F;
434	        alpha       = &alpha_half;
435	        beta        = &beta_half;
436	    }
437	
438	    cublasLtMatmulDesc_t   operationDesc = NULL;
439	    cublasLtMatrixLayout_t Adesc = NULL, Bdesc = NULL, Cdesc = NULL;
440	    cublasLtEpilogue_t     epi = CUBLASLT_EPILOGUE_BIAS;
441	    cublasLtMatrixLayoutCreate(&Adesc, Atype, (transa == CUBLAS_OP_N) ? m : k, (transa == CUBLAS_OP_N) ? k : m, lda);
442	    cublasLtMatrixLayoutCreate(&Bdesc, Btype, (transb == CUBLAS_OP_N) ? k : n, (transb == CUBLAS_OP_N) ? n : k, ldb);
443	    cublasLtMatrixLayoutCreate(&Cdesc, Ctype, m, n, ldc);
444	
445	    cublasLtMatmulDescCreate(&operationDesc, computeType, scaleType);
446	    cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSA, &transa, sizeof(cublasOperation_t));
447	    cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSB, &transb, sizeof(cublasOperation_t));
448	    cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_EPILOGUE, &epi, sizeof(cublasLtEpilogue_t));
449	    cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_BIAS_POINTER, &bias, sizeof(const void*));
450	    check_cuda_error(cublasLtMatmul(
451	        cublaslt_handle_, operationDesc, alpha, A, Adesc, B, Bdesc, beta, C, Cdesc, C, Cdesc, NULL, NULL, 0, stream_));
452	    cublasLtMatrixLayoutDestroy(Adesc);
453	    cublasLtMatrixLayoutDestroy(Bdesc);
454	    cublasLtMatrixLayoutDestroy(Cdesc);
455	    cublasLtMatmulDescDestroy(operationDesc);
456	}
