639	#ifdef SPARSITY_ENABLED
640	void cublasMMWrapper::SpGemm(cublasOperation_t transa,
641	                             cublasOperation_t transb,
642	                             const int         m,
643	                             const int         n,
644	                             const int         k,
645	                             const void*       A,
646	                             const void*       B,
647	                             void*             C)
648	{
649	    if (Atype_ != CUDA_R_16F || Btype_ != CUDA_R_16F || Ctype_ != CUDA_R_16F) {
650	        throw std::runtime_error("\n[FT][ERROR] sparse GEMM only supports FP16 data type now.");
651	    }
652	    static bool not_printed_fp32_accumulation_warning = true;
653	    if (computeType_ != CUDA_R_16F && not_printed_fp32_accumulation_warning) {
654	        printf("[FT][WARNING] cublasMMWrapper sets to FP32 compute type, "
655	               "but sparse gemm will use FP16 compute type since cusparselt "
656	               "supports FP16 accumulation only.\n");
657	        not_printed_fp32_accumulation_warning = false;
658	    }
659	    cusparseOrder_t     order = CUSPARSE_ORDER_COL;
660	    cusparseOperation_t opA = (transa == CUBLAS_OP_N) ? CUSPARSE_OPERATION_NON_TRANSPOSE : CUSPARSE_OPERATION_TRANSPOSE;
661	    cusparseOperation_t opB = (transb == CUBLAS_OP_N) ? CUSPARSE_OPERATION_NON_TRANSPOSE : CUSPARSE_OPERATION_TRANSPOSE;
662	    cusparseComputeType compute_type = CUSPARSE_COMPUTE_16F;
663	    cusparseLtMatmulDescriptor_t   matmul;
664	    cusparseLtMatmulAlgSelection_t alg_sel;
665	    cusparseLtMatmulPlan_t         plan;
666	
667	    bool     is_rowmajor    = (order == CUSPARSE_ORDER_ROW);
668	    bool     isA_transposed = (opA != CUSPARSE_OPERATION_NON_TRANSPOSE);
669	    bool     isB_transposed = (opB != CUSPARSE_OPERATION_NON_TRANSPOSE);
670	    auto     num_A_rows     = (isA_transposed) ? k : m;
671	    auto     num_A_cols     = (isA_transposed) ? m : k;
672	    auto     num_B_rows     = (isB_transposed) ? n : k;
673	    auto     num_B_cols     = (isB_transposed) ? k : n;
674	    auto     num_C_rows     = m;
675	    auto     num_C_cols     = n;
676	    unsigned alignment      = 16;
677	    auto     lda            = (is_rowmajor) ? num_A_cols : num_A_rows;
678	    auto     ldb            = (is_rowmajor) ? num_B_cols : num_B_rows;
679	    auto     ldc            = (is_rowmajor) ? num_C_cols : num_C_rows;
680	    float    _alpha(1.0f);
681	    float    _beta(0.0f);
682	
683	    char mark[256];
684	    sprintf(mark, "%d_%d_%d_%d", 1, m, n, k);
685	    if (sp_mat_A_desc_map_.find(mark) != sp_mat_A_desc_map_.end()) {
686	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
687	                                                      &matmul,
688	                                                      opA,
689	                                                      opB,
690	                                                      &sp_mat_A_desc_map_[mark],
691	                                                      &sp_mat_B_desc_map_[mark],
692	                                                      &sp_mat_C_desc_map_[mark],
693	                                                      &sp_mat_C_desc_map_[mark],
694	                                                      compute_type))
695	    }
696	    else {
697	        // initializing MatDesc takes a lot of time
698	        cusparseLtMatDescriptor_t matA, matB, matC;
699	        sp_mat_A_desc_map_[mark] = matA;
700	        sp_mat_B_desc_map_[mark] = matB;
701	        sp_mat_C_desc_map_[mark] = matC;
702	        CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(&cusparselt_handle_,
703	                                                          &sp_mat_A_desc_map_[mark],
704	                                                          num_A_rows,
705	                                                          num_A_cols,
706	                                                          lda,
707	                                                          alignment,
708	                                                          Atype_,
709	                                                          order,
710	                                                          CUSPARSELT_SPARSITY_50_PERCENT))
711	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
712	            &cusparselt_handle_, &sp_mat_B_desc_map_[mark], num_B_rows, num_B_cols, ldb, alignment, Btype_, order))
713	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
714	            &cusparselt_handle_, &sp_mat_C_desc_map_[mark], num_C_rows, num_C_cols, ldc, alignment, Ctype_, order))
715	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
716	                                                      &matmul,
717	                                                      opA,
718	                                                      opB,
719	                                                      &sp_mat_A_desc_map_[mark],
720	                                                      &sp_mat_B_desc_map_[mark],
721	                                                      &sp_mat_C_desc_map_[mark],
722	                                                      &sp_mat_C_desc_map_[mark],
723	                                                      compute_type))
724	    }
725	    mu_->lock();
726	    CHECK_CUSPARSE(
727	        cusparseLtMatmulAlgSelectionInit(&cusparselt_handle_, &alg_sel, &matmul, CUSPARSELT_MATMUL_ALG_DEFAULT))
728	    int alg = cublas_algo_map_->getSpAlgo(1, num_A_rows, num_B_cols, num_A_cols);
729	    CHECK_CUSPARSE(cusparseLtMatmulAlgSetAttribute(
730	        &cusparselt_handle_, &alg_sel, CUSPARSELT_MATMUL_ALG_CONFIG_ID, &alg, sizeof(alg)))
731	    size_t workspace_size;
732	    CHECK_CUSPARSE(cusparseLtMatmulGetWorkspace(&cusparselt_handle_, &alg_sel, &workspace_size))
733	    CHECK_CUSPARSE(cusparseLtMatmulPlanInit(&cusparselt_handle_, &plan, &matmul, &alg_sel, workspace_size))
734	
735	    void*        d_workspace = nullptr;
736	    int          num_streams = 1;
737	    cudaStream_t streams[1]  = {stream_};
738	    CHECK_CUSPARSE(
739	        cusparseLtMatmul(&cusparselt_handle_, &plan, &_alpha, A, B, &_beta, C, C, d_workspace, streams, num_streams))
740	    CHECK_CUSPARSE(cusparseLtMatmulPlanDestroy(&plan))
741	    sync_check_cuda_error();
742	    mu_->unlock();
743	}
