788	std::pair<bool, cublasLtMatmulAlgo_t> cublasMMWrapper::findBestAlgo(cublasLtHandle_t       lightHandle,
789	                                                                    cublasLtMatmulDesc_t   computeDesc,
790	                                                                    const void*            alpha,
791	                                                                    const void*            A,
792	                                                                    cublasLtMatrixLayout_t Adesc,
793	                                                                    const void*            B,
794	                                                                    cublasLtMatrixLayout_t Bdesc,
795	                                                                    const void*            beta,
796	                                                                    const void*            C,
797	                                                                    cublasLtMatrixLayout_t Cdesc,
798	                                                                    void*                  D,
799	                                                                    cublasLtMatrixLayout_t Ddesc,
800	                                                                    cudaStream_t           stream)
801	{
802	#if (CUBLAS_VERSION) < 11601
803	    FT_CHECK_WITH_INFO(false, "CUBLAS version too low.");
804	    return {false, cublasLtMatmulAlgo_t{}};
805	#else
806	    size_t returnSize;
807	    int32_t pointer_mode;
808	    cublasLtMatmulDescGetAttribute(
809	        computeDesc, CUBLASLT_MATMUL_DESC_POINTER_MODE, &pointer_mode, sizeof(pointer_mode), &returnSize);
810	
811	    std::vector<cublasLtMatmulHeuristicResult_t> heuristics(200);
812	    cublasLtMatmulPreference_t preference;
813	    check_cuda_error(cublasLtMatmulPreferenceCreate(&preference));
814	    check_cuda_error(cublasLtMatmulPreferenceInit(preference));
815	    uint64_t workspace_size = CUBLAS_WORKSPACE_SIZE;
816	    check_cuda_error(cublasLtMatmulPreferenceSetAttribute(
817	        preference, CUBLASLT_MATMUL_PREF_MAX_WORKSPACE_BYTES, &workspace_size, sizeof(workspace_size)));
818	#if (CUBLAS_VERSION) <= 12000
819	    uint32_t pointer_mode_mask = 0;
820	    check_cuda_error(cublasLtMatmulPreferenceSetAttribute(
821	        preference, CUBLASLT_MATMUL_PREF_EPILOGUE_MASK, &pointer_mode_mask, sizeof(pointer_mode_mask)));
822	#endif
823	
824	    int return_count = 0;
825	    auto ret = cublasLtMatmulAlgoGetHeuristic(lightHandle,
826	                                              computeDesc,
827	                                              Adesc,
828	                                              Bdesc,
829	                                              Cdesc,
830	                                              Ddesc,
831	                                              preference,
832	                                              heuristics.size(),
833	                                              heuristics.data(),
834	                                              &return_count);
835	    heuristics.resize(return_count);
836	
837	    std::map<int, std::vector<float>> algo_results;
838	    for (const auto& heuristic : heuristics) {
839	        cublasLtMatmulAlgo_t algo = heuristic.algo;
840	        int32_t algo_id;
841	        cublasLtMatmulAlgoConfigGetAttribute(&algo, CUBLASLT_ALGO_CONFIG_ID, &algo_id, sizeof(algo_id), &returnSize);
842	
843	        cudaEvent_t start_event, stop_event;
844	        cudaEventCreate(&start_event);
845	        cudaEventCreate(&stop_event);
846	
847	        float my_alpha = 1.0f;
848	        float my_beta = 0.0f;
849	
850	        for (int i = 0; i < 11; i++) {
851	            float duration_ms;
852	            cudaEventRecord(start_event, stream);
853	            check_cuda_error(cublasLtMatmul(lightHandle,
854	                                            computeDesc,
855	                                            alpha,
856	                                            A,
857	                                            Adesc,
858	                                            B,
859	                                            Bdesc,
860	                                            beta,
861	                                            C,
862	                                            Cdesc,
863	                                            D,
864	                                            Ddesc,
865	                                            &algo,
866	                                            cublas_workspace_,
867	                                            CUBLAS_WORKSPACE_SIZE,
868	                                            stream));
869	            cudaEventRecord(stop_event, stream);
870	            cudaEventSynchronize(stop_event);
871	            cudaEventElapsedTime(&duration_ms, start_event, stop_event);
872	
873	            algo_results[algo_id].push_back(duration_ms);
874	        }
875	        std::sort(algo_results[algo_id].begin(), algo_results[algo_id].end());
876	    }
877	
878	    cublasLtMatmulHeuristicResult_t result;
879	    float best_time = INFINITY;
880	    for (const auto& heuristic : heuristics) {
881	        cublasLtMatmulAlgo_t algo = heuristic.algo;
882	        int32_t algo_id;
883	        cublasLtMatmulAlgoConfigGetAttribute(&algo, CUBLASLT_ALGO_CONFIG_ID, &algo_id, sizeof(algo_id), &returnSize);
884	        const auto& results = algo_results[algo_id];
885	
886	        if (results.size() > 0 && results[5] < best_time) {
887	            best_time = results[5];
888	            result = heuristic;
889	        }
890	    }
891	
892	    return {best_time != INFINITY, result.algo};
893	#endif
894	}
