970	void cublasMMWrapper::_Int8Gemm(const int     m,
971	                                const int     n,
972	                                const int     k,
973	                                const int8_t* A,
974	                                const int     lda,
975	                                const int8_t* B,
976	                                const int     ldb,
977	                                void*         C,
978	                                const int     ldc,
979	                                const void*   alpha,
980	                                const int     mode,
981	                                const bool    per_column_scaling)
982	{
983	    /* mode:
984	     *  - 0: int8 * int8 -> int32 -> int8
985	     *  - 1: int8 * int8 -> int32 -> int32
986	     */
987	#if (CUBLAS_VERSION) < 11601
988	    FT_CHECK_WITH_INFO(false, "CUBLAS version too low.");
989	#else
990	
991	    mu_->lock();
992	    const auto op_a = CUBLAS_OP_T;
993	    const auto op_b = CUBLAS_OP_N;
994	    const auto dataType = CUDA_R_8I;
995	    const auto resultType = mode == 0 ? CUDA_R_8I : CUDA_R_32I;
996	    const auto computeType = CUBLAS_COMPUTE_32I;
997	    const auto scaleType = mode == 0 ? CUDA_R_32F : CUDA_R_32I;
998	    const int batch_count = 1;
999	    const void* beta;
1000	
1001	    int findAlgo = cublas_algo_map_->isExist(batch_count, m, n, k, getCublasDataType(dataType));
1002	
1003	    cublasLtMatmulAlgo_info info = cublas_algo_map_->getAlgo(batch_count, m, n, k, getCublasDataType(dataType));
1004	
1005	    cublasLtMatmulDesc_t operationDesc = NULL;
1006	    cublasLtMatrixLayout_t Adesc = NULL, Bdesc = NULL, Cdesc = NULL;
1007	
1008	    // --------------------------------------
1009	    // Create descriptors for the original matrices
1010	    check_cuda_error(cublasLtMatrixLayoutCreate(&Adesc, dataType, k, m, lda));
1011	    check_cuda_error(cublasLtMatrixLayoutCreate(&Bdesc, dataType, k, n, ldb));
1012	    check_cuda_error(cublasLtMatrixLayoutCreate(&Cdesc, resultType, m, n, ldc));
1013	
1014	    check_cuda_error(cublasLtMatmulDescCreate(&operationDesc, computeType, scaleType));
1015	
1016	    auto pointer_mode = CUBLASLT_POINTER_MODE_HOST;
1017	    if (mode == 0) {
1018	        pointer_mode =
1019	            per_column_scaling ? CUBLASLT_POINTER_MODE_ALPHA_DEVICE_VECTOR_BETA_HOST : CUBLASLT_POINTER_MODE_DEVICE;
1020	    }
1021	    check_cuda_error(
1022	        cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSA, &op_a, sizeof(cublasOperation_t)));
1023	    check_cuda_error(
1024	        cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSB, &op_b, sizeof(cublasOperation_t)));
1025	    check_cuda_error(
1026	        cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSC, &op_b, sizeof(cublasOperation_t)));
1027	    check_cuda_error(cublasLtMatmulDescSetAttribute(
1028	        operationDesc, CUBLASLT_MATMUL_DESC_POINTER_MODE, &pointer_mode, sizeof(pointer_mode)));
1029	
1030	    const int32_t int_one = 1;
1031	    const int32_t int_zero = 0;
1032	    const float float_zero = 0;
1033	    if (mode == 0) {
1034	        beta = per_column_scaling ? &float_zero : NULL;
1035	    }
1036	    else {
1037	        alpha = &int_one;
1038	        beta = &int_zero;
1039	    }
1040	
1041	    cublasLtMatmulAlgo_t algo;
1042	    void* workSpace = cublas_workspace_;
1043	    int workspaceSize = cublas_workspace_ == NULL ? 0 : CUBLAS_WORKSPACE_SIZE;
1044	
1045	    sync_check_cuda_error();
1046	    auto ret = cublasLtMatmulWrapper(cublaslt_handle_,
1047	                                     operationDesc,
1048	                                     alpha,
1049	                                     A,
1050	                                     Adesc,
1051	                                     B,
1052	                                     Bdesc,
1053	                                     beta,
1054	                                     C,
1055	                                     Cdesc,
1056	                                     C,
1057	                                     Cdesc,
1058	                                     NULL,
1059	                                     workSpace,
1060	                                     workspaceSize,
1061	                                     stream_);
1062	    check_cuda_error(ret);
1063	    sync_check_cuda_error();
1064	
1065	    cublasLtMatmulDescDestroy(operationDesc);
1066	    cublasLtMatrixLayoutDestroy(Adesc);
1067	    cublasLtMatrixLayoutDestroy(Bdesc);
1068	    cublasLtMatrixLayoutDestroy(Cdesc);
1069	    sync_check_cuda_error();
1070	    mu_->unlock();
1071	#endif
1072	}
