208	void Gemm::gemm(const GemmOp   transa,
209	                const GemmOp   transb,
210	                const size_t   m,
211	                const size_t   n,
212	                const size_t   k,
213	                const void*    A,
214	                const DataType Atype,
215	                const size_t   lda,
216	                const void*    B,
217	                const DataType Btype,
218	                const size_t   ldb,
219	                void*          C,
220	                const DataType Ctype,
221	                const size_t   ldc,
222	                const float    alpha,
223	                const float    beta)
224	{
225	    FT_LOG_TRACE("Gemm::gemm [m=%ld, n=%ld, k=%ld, lda=%ld, ldb=%ld, ldc=%ld]", m, n, k, lda, ldb, ldc);
226	
227	    // Implementation copied from cublasMMWrapper::Gemm
228	    // Switch A and B since both cublas and cublasLt assume a column major layout,
229	    // while A and B are both row major layout.
230	    const void* a_data_ptr = B;
231	    const void* b_data_ptr = A;
232	
233	    cublasOperation_t a_op = getCublasOperation(transb);
234	    cublasOperation_t b_op = getCublasOperation(transa);
235	
236	    cudaDataType_t a_type = getCublasDataType(Btype);
237	    cudaDataType_t b_type = getCublasDataType(Atype);
238	    cudaDataType_t c_type = getCublasDataType(Ctype);
239	
240	    // swap m and n
241	    const size_t _m = n;
242	    const size_t _n = m;
243	
244	    // swap lda and ldb;
245	    const size_t _lda = ldb;
246	    const size_t _ldb = lda;
247	
248	    mutex_->lock();
249	    // Use cublas as default in FP32 and cublasLt as default in FP16
250	    bool is_fp16_compute_type = compute_type_ == TYPE_FP16;
251	    bool using_cublasLt       = Atype == TYPE_FP16;
252	    int  batch_count          = 1;
253	
254	    half        h_alpha = (half)alpha;
255	    half        h_beta  = (half)beta;
256	    const void* alpha_ptr =
257	        is_fp16_compute_type ? reinterpret_cast<const void*>(&h_alpha) : reinterpret_cast<const void*>(&alpha);
258	    const void* beta_ptr =
259	        is_fp16_compute_type ? reinterpret_cast<const void*>(&h_beta) : reinterpret_cast<const void*>(&beta);
260	
261	    // TODO: unify CUBLAS_DATA_TYPE and DataType.
262	    int findAlgo =
263	        cublas_algo_map_->isExist(batch_count, _m, _n, k, (a_type == CUDA_R_16F) ? HALF_DATATYPE : FLOAT_DATATYPE);
264	    cublasLtMatmulAlgo_info info =
265	        cublas_algo_map_->getAlgo(batch_count, _m, _n, k, (a_type == CUDA_R_16F) ? HALF_DATATYPE : FLOAT_DATATYPE);
266	    if (findAlgo) {
267	        using_cublasLt = (info.stages != -1);
268	    }
269	
270	    if (using_cublasLt) {
271	        const size_t a_rows = (a_op == getCublasOperation(GEMM_OP_N)) ? _m : k;
272	        const size_t a_cols = (a_op == getCublasOperation(GEMM_OP_N)) ? k : _m;
273	        const size_t b_rows = (b_op == getCublasOperation(GEMM_OP_N)) ? k : _n;
274	        const size_t b_cols = (b_op == getCublasOperation(GEMM_OP_N)) ? _n : k;
275	
276	        cublasLtMatmulDesc_t   matmul_desc = NULL;
277	        cublasLtMatrixLayout_t a_desc = NULL, b_desc = NULL, c_desc = NULL;
278	        cudaDataType_t         scale_type   = getCublasDataType(compute_type_);
279	        auto                   compute_type = getCublasComputeType(compute_type_);
280	
281	        // --------------------------------------
282	        // Create descriptors for the original matrices
283	        cublasLtMatrixLayoutCreate(&a_desc, a_type, a_rows, a_cols, _lda);
284	        cublasLtMatrixLayoutCreate(&b_desc, b_type, b_rows, b_cols, _ldb);
285	        cublasLtMatrixLayoutCreate(&c_desc, c_type, _m, _n, ldc);
286	#if (CUDART_VERSION >= 11000)
287	        cublasLtMatmulDescCreate(&matmul_desc, compute_type, scale_type);
288	#else
289	        cublasLtMatmulDescCreate(&matmul_desc, compute_type);
290	#endif
291	
292	        cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSA, &a_op, sizeof(cublasOperation_t));
293	        cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSB, &b_op, sizeof(cublasOperation_t));
294	
295	        cublasLtMatmulAlgo_t algo;
296	        void*                workspace      = workspace_;
297	        int                  workspace_size = workspace_ == nullptr ? 0 : CUBLAS_WORKSPACE_SIZE;
298	        if (findAlgo) {
299	            if (info.workspaceSize > workspace_size) {
300	                findAlgo = 0;
301	            }
302	            else {
303	                cublasLtMatmulAlgoInit(
304	                    cublaslt_handle_, compute_type, scale_type, a_type, b_type, c_type, c_type, info.algoId, &algo);
305	                cublasLtMatmulAlgoConfigSetAttribute(
306	                    &algo, CUBLASLT_ALGO_CONFIG_CUSTOM_OPTION, &(info.customOption), sizeof(info.customOption));
307	                cublasLtMatmulAlgoConfigSetAttribute(
308	                    &algo, CUBLASLT_ALGO_CONFIG_TILE_ID, &(info.tile), sizeof(info.tile));
309	                cublasLtMatmulAlgoConfigSetAttribute(
310	                    &algo, CUBLASLT_ALGO_CONFIG_SPLITK_NUM, &(info.splitK_val), sizeof(info.splitK_val));
311	                cublasLtMatmulAlgoConfigSetAttribute(
312	                    &algo, CUBLASLT_ALGO_CONFIG_CTA_SWIZZLING, &(info.swizzle), sizeof(info.swizzle));
313	                cublasLtMatmulAlgoConfigSetAttribute(
314	                    &algo, CUBLASLT_ALGO_CONFIG_REDUCTION_SCHEME, &(info.reductionScheme), sizeof(int));
315	#if (CUDART_VERSION >= 11000)
316	                cublasLtMatmulAlgoConfigSetAttribute(
317	                    &algo, CUBLASLT_ALGO_CONFIG_STAGES_ID, &(info.stages), sizeof(info.stages));
318	#endif
319	            }
320	        }
321	
322	        cublasLtMatmul(cublaslt_handle_,
323	                       matmul_desc,
324	                       alpha_ptr,
325	                       a_data_ptr,
326	                       a_desc,
327	                       b_data_ptr,
328	                       b_desc,
329	                       beta_ptr,
330	                       C,
331	                       c_desc,
332	                       C,
333	                       c_desc,
334	                       (findAlgo == 1 ? (&algo) : NULL),
335	                       workspace,
336	                       workspace_size,
337	                       stream_);
338	
339	        cublasLtMatmulDescDestroy(matmul_desc);
340	        cublasLtMatrixLayoutDestroy(a_desc);
341	        cublasLtMatrixLayoutDestroy(b_desc);
342	        cublasLtMatrixLayoutDestroy(c_desc);
343	        sync_check_cuda_error();
344	    }
345	    else {
346	        cudaDataType_t compute_type = getCublasDataType(compute_type_);
347	        int            cublas_algo  = info.algoId;
348	        check_cuda_error(cublasGemmEx(cublas_handle_,
349	                                      a_op,
350	                                      b_op,
351	                                      _m,
352	                                      _n,
353	                                      k,
354	                                      alpha_ptr,
355	                                      a_data_ptr,
356	                                      a_type,
357	                                      _lda,
358	                                      b_data_ptr,
359	                                      b_type,
360	                                      _ldb,
361	                                      beta_ptr,
362	                                      C,
363	                                      c_type,
364	                                      ldc,
365	                                      compute_type,
366	                                      static_cast<cublasGemmAlgo_t>(cublas_algo)));
367	        sync_check_cuda_error();
368	    }
369	    mutex_->unlock();
370	}
