408	void Gemm::batchedGemm(const GemmOp       transa,
409	                       const GemmOp       transb,
410	                       const size_t       m,
411	                       const size_t       n,
412	                       const size_t       k,
413	                       const void* const* A,
414	                       const DataType     Atype,
415	                       const size_t       lda,
416	                       const void* const* B,
417	                       const DataType     Btype,
418	                       const size_t       ldb,
419	                       void* const*       C,
420	                       const DataType     Ctype,
421	                       const size_t       ldc,
422	                       const size_t       batch_size,
423	                       const float        alpha,
424	                       const float        beta)
425	{
426	    FT_LOG_TRACE(
427	        "Gemm::batchedGemm [b=%ld m=%ld, n=%ld, k=%ld, lda=%ld, ldb=%ld, ldc=%ld]", batch_size, m, n, k, lda, ldb, ldc);
428	
429	    // Switch A and B.
430	    const void* const* a_data_ptr = B;
431	    const void* const* b_data_ptr = A;
432	
433	    cublasOperation_t a_op = getCublasOperation(transb);
434	    cublasOperation_t b_op = getCublasOperation(transa);
435	
436	    cudaDataType_t a_type = getCublasDataType(Btype);
437	    cudaDataType_t b_type = getCublasDataType(Atype);
438	    cudaDataType_t c_type = getCublasDataType(Ctype);
439	
440	    // swap m and n, lda and ldb
441	    const size_t _m   = n;
442	    const size_t _n   = m;
443	    const size_t _lda = ldb;
444	    const size_t _ldb = lda;
445	
446	    half h_alpha = (half)alpha;
447	    half h_beta  = (half)beta;
448	
449	    mutex_->lock();
450	    bool        is_fp16_compute_type = compute_type_ == TYPE_FP16;
451	    const void* alpha_ptr =
452	        is_fp16_compute_type ? reinterpret_cast<const void*>(&h_alpha) : reinterpret_cast<const void*>(&alpha);
453	    const void* beta_ptr =
454	        is_fp16_compute_type ? reinterpret_cast<const void*>(&h_beta) : reinterpret_cast<const void*>(&beta);
455	    cublasLtMatmulAlgo_info info =
456	        cublas_algo_map_->getAlgo(batch_size, m, n, k, (a_type == CUDA_R_16F) ? HALF_DATATYPE : FLOAT_DATATYPE);
457	
458	    check_cuda_error(cublasGemmBatchedEx(cublas_handle_,
459	                                         a_op,
460	                                         b_op,
461	                                         _m,
462	                                         _n,
463	                                         k,
464	                                         alpha_ptr,
465	                                         a_data_ptr,
466	                                         a_type,
467	                                         _lda,
468	                                         b_data_ptr,
469	                                         b_type,
470	                                         _ldb,
471	                                         beta_ptr,
472	                                         C,
473	                                         c_type,
474	                                         ldc,
475	                                         batch_size,
476	                                         getCublasComputeType(compute_type_),
477	                                         static_cast<cublasGemmAlgo_t>(info.algoId)));
478	    mutex_->unlock();
479	}
