858	
859	void SpGemm::gemm(const GemmOp   transa,
860	                  const GemmOp   transb,
861	                  const size_t   m,
862	                  const size_t   n,
863	                  const size_t   k,
864	                  const void*    A,
865	                  const DataType Atype,
866	                  const size_t   lda,
867	                  const void*    B,
868	                  const DataType Btype,
869	                  const size_t   ldb,
870	                  void*          C,
871	                  const DataType Ctype,
872	                  const size_t   ldc,
873	                  const float    alpha,
874	                  const float    beta)
875	{
876	    FT_LOG_TRACE("SpGemm::gemm [m=%ld, n=%ld, k=%ld, lda=%ld, ldb=%ld, ldc=%ld]", m, n, k, lda, ldb, ldc);
877	    checkDataTypeValidity(Atype);
878	    checkDataTypeValidity(Btype);
879	    checkDataTypeValidity(Ctype);
880	    checkDataTypeValidity(compute_type_);
881	
882	    if (useBaseGemm(1, m, n, k)) {
883	        // Compute by the base GEMM.
884	        Gemm::gemm(transa, transb, m, n, k, A, Atype, lda, B, Btype, ldb, C, Ctype, ldc, alpha, beta);
885	        return;
886	    }
887	
888	    // Switch A/B due to column major layout in computation.
889	    //  Typical usecase of Gemm family is to compute Y = X * W where X is an
890	    //  input tensor and W is a kernel weight. Compression takes a lot time
891	    //  so only the kernel weight (which is fixed in inference time) can be
892	    //  sparse. Using B as sparse seems not stable, unfortunately.
893	    //  (e.g. caching matrix descriptions is not correctly working.)
894	    //  Thus, SpGemm considers a column major layout in computation to make
895	    //  C^T = B^T * A^T, where a kernel weight "B" is located at the front.
896	    const void* a_data = B;
897	    const void* b_data = A;
898	
899	    cusparseOrder_t order = CUSPARSE_ORDER_COL;
900	
901	    cusparseOperation_t opA = getCusparseOperation(transb);
902	    cusparseOperation_t opB = getCusparseOperation(transa);
903	
904	    cudaDataType_t a_type = getCublasDataType(Btype);
905	    cudaDataType_t b_type = getCublasDataType(Atype);
906	    cudaDataType_t c_type = getCublasDataType(Ctype);
907	
908	    const size_t _m   = n;
909	    const size_t _n   = m;
910	    const size_t _lda = ldb;
911	    const size_t _ldb = lda;
912	
913	    const size_t a_rows = (opA == CUSPARSE_OPERATION_NON_TRANSPOSE) ? _m : k;
914	    const size_t a_cols = (opA == CUSPARSE_OPERATION_NON_TRANSPOSE) ? k : _m;
915	    const size_t b_rows = (opB == CUSPARSE_OPERATION_NON_TRANSPOSE) ? k : _n;
916	    const size_t b_cols = (opB == CUSPARSE_OPERATION_NON_TRANSPOSE) ? _n : k;
917	    const size_t c_rows = _m;
918	    const size_t c_cols = _n;
919	
920	    const unsigned      alignment    = 16;
921	    cusparseComputeType compute_type = getCusparseComputeType(compute_type_);
922	
923	    cusparseLtMatmulDescriptor_t   matmul;
924	    cusparseLtMatmulAlgSelection_t alg_sel;
925	    cusparseLtMatmulPlan_t         plan;
926	
927	    char mark[256];
928	    sprintf(mark, "%d_%ld_%ld_%ld_%s_%s", 1, m, n, k, getGemmOpString(transb).c_str(), getGemmOpString(transa).c_str());
929	    if (a_desc_map_.find(mark) != a_desc_map_.end()) {
930	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
931	                                                      &matmul,
932	                                                      opA,
933	                                                      opB,
934	                                                      &a_desc_map_[mark],
935	                                                      &b_desc_map_[mark],
936	                                                      &c_desc_map_[mark],
937	                                                      &c_desc_map_[mark],
938	                                                      compute_type));
939	    }
940	    else {
941	        // initializing MatDesc takes a lot of time
942	        cusparseLtMatDescriptor_t a_desc, b_desc, c_desc;
943	        a_desc_map_[mark] = a_desc;
944	        b_desc_map_[mark] = b_desc;
945	        c_desc_map_[mark] = c_desc;
946	        CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(&cusparselt_handle_,
947	                                                          &a_desc_map_[mark],
948	                                                          a_rows,
949	                                                          a_cols,
950	                                                          _lda,
951	                                                          alignment,
952	                                                          a_type,
953	                                                          order,
954	                                                          CUSPARSELT_SPARSITY_50_PERCENT));
955	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
956	            &cusparselt_handle_, &b_desc_map_[mark], b_rows, b_cols, _ldb, alignment, b_type, order));
957	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
958	            &cusparselt_handle_, &c_desc_map_[mark], c_rows, c_cols, ldc, alignment, c_type, order));
959	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
960	                                                      &matmul,
961	                                                      opA,
962	                                                      opB,
963	                                                      &a_desc_map_[mark],
964	                                                      &b_desc_map_[mark],
965	                                                      &c_desc_map_[mark],
966	                                                      &c_desc_map_[mark],
967	                                                      compute_type));
968	    }
969	
970	    mutex_->lock();
971	    CHECK_CUSPARSE(
972	        cusparseLtMatmulAlgSelectionInit(&cusparselt_handle_, &alg_sel, &matmul, CUSPARSELT_MATMUL_ALG_DEFAULT));
973	    int alg = cublas_algo_map_->getSpAlgo(1, a_rows, b_cols, a_cols);
974	    CHECK_CUSPARSE(cusparseLtMatmulAlgSetAttribute(
975	        &cusparselt_handle_, &alg_sel, CUSPARSELT_MATMUL_ALG_CONFIG_ID, &alg, sizeof(alg)));
976	    size_t workspace_size;
977	    CHECK_CUSPARSE(cusparseLtMatmulGetWorkspace(&cusparselt_handle_, &alg_sel, &workspace_size));
978	    CHECK_CUSPARSE(cusparseLtMatmulPlanInit(&cusparselt_handle_, &plan, &matmul, &alg_sel, workspace_size));
979	
980	    void*        d_workspace = nullptr;  // Can we use the workspace of the class?
981	    int          num_streams = 1;
982	    cudaStream_t streams[1]  = {stream_};
983	    CHECK_CUSPARSE(cusparseLtMatmul(
984	        &cusparselt_handle_, &plan, &alpha, a_data, b_data, &beta, C, C, d_workspace, streams, num_streams))
985	    CHECK_CUSPARSE(cusparseLtMatmulPlanDestroy(&plan))
986	    mutex_->unlock();
987	    sync_check_cuda_error();
988	}
