1106	void pruneMatrixB(void* data, const cudaStream_t& stream, const size_t k, const size_t n, const GemmOp trans)
1107	{
1108	    FT_LOG_TRACE("Prune matrix B [k=%ld, n=%ld, op=%s]", k, n, getGemmOpString(trans).c_str());
1109	
1110	    // Due to A/B switching, the matrix B will be used as a matrix A.
1111	    const cusparseOrder_t order     = CUSPARSE_ORDER_COL;
1112	    const size_t          rows      = (trans == GEMM_OP_N) ? n : k;
1113	    const size_t          cols      = (trans == GEMM_OP_N) ? k : n;
1114	    const size_t          ld        = rows;
1115	    const unsigned        alignment = 16;
1116	
1117	    const cusparseLtPruneAlg_t prune_alg = CUSPARSELT_PRUNE_SPMMA_STRIP;
1118	    const cusparseOperation_t  op        = getCusparseOperation(trans);
1119	    const cudaDataType_t       dtype     = CUDA_R_16F;  // fixed under cusparselt == 0.2.0.
1120	
1121	    // 0: B is sparse,  1: A is sparse
1122	    // B matrix will be used as A matrix at the SpGemm::gemm.
1123	    const int is_sparse_a = 1;
1124	
1125	    // TODO: Let the resource manager handle GPU-related resources later.
1126	    cusparseLtHandle_t handle;
1127	    CHECK_CUSPARSE(cusparseLtInit(&handle));
1128	    cusparseLtMatDescriptor_t mat_desc;
1129	    CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(
1130	        &handle, &mat_desc, rows, cols, ld, alignment, dtype, order, CUSPARSELT_SPARSITY_50_PERCENT));
1131	    CHECK_CUSPARSE(cusparseLtSpMMAPrune2(&handle, &mat_desc, is_sparse_a, op, data, data, prune_alg, stream));
1132	    CHECK_CUSPARSE(cusparseLtMatDescriptorDestroy(&mat_desc));
1133	    CHECK_CUSPARSE(cusparseLtDestroy(&handle));
1134	}
1135	
1136	size_t compressMatrixB(void**              output,
1137	                       IAllocator&         allocator,
1138	                       const cudaStream_t& stream,
1139	                       const void*         input,
1140	                       const size_t        k,
1141	                       const size_t        n,
1142	                       const GemmOp        trans)
1143	{
1144	    FT_LOG_TRACE("compressMatrix [k=%ld, n=%ld, dtype=FP16]", k, n);
1145	
1146	    // swap A/B due to column/row major layout mismatch.
1147	    cusparseOrder_t order = CUSPARSE_ORDER_COL;
1148	    const size_t    rows  = (trans == GEMM_OP_N) ? n : k;
1149	    const size_t    cols  = (trans == GEMM_OP_N) ? k : n;
1150	    const size_t    ld    = rows;
1151	
1152	    cudaDataType_t            dtype    = CUDA_R_16F;  // fixed under cusparselt == 0.2.0.
1153	    cusparseLtSparsity_t      sparsity = CUSPARSELT_SPARSITY_50_PERCENT;
1154	    cusparseOperation_t       op       = getCusparseOperation(trans);
1155	    cusparseLtMatDescriptor_t mat_desc;
1156	    const unsigned            alignment   = 16;
1157	    const int                 is_sparse_a = 1;  // 0: B is sparse,  1: A is sparse
1158	
1159	    cusparseLtHandle_t handle;
1160	    CHECK_CUSPARSE(cusparseLtInit(&handle));
1161	
1162	    CHECK_CUSPARSE(
1163	        cusparseLtStructuredDescriptorInit(&handle, &mat_desc, rows, cols, ld, alignment, dtype, order, sparsity))
1164	
1165	    size_t compressed_size = 0;
1166	    CHECK_CUSPARSE(cusparseLtSpMMACompressedSize2(&handle, &mat_desc, &compressed_size));
1167	    if (compressed_size == 0) {
1168	        throw GemmInvalidException("Fail to compute correct compressed_size, got 0. This error may be "
1169	                                   "caused by a too small input matrix.");
1170	    }
1171	
1172	    *output = allocator.malloc(compressed_size, false);
1173	    CHECK_CUSPARSE(cusparseLtSpMMACompress2(&handle, &mat_desc, is_sparse_a, op, input, *output, stream))
1174	
1175	    CHECK_CUSPARSE(cusparseLtMatDescriptorDestroy(&mat_desc));
1176	    CHECK_CUSPARSE(cusparseLtDestroy(&handle));
1177	    return compressed_size;
1178	}
1179	
1180	#endif
